export const SEO_PAGES: SeoPage[] = [
  ...SEO_PAGES_PART_0,
  ...SEO_PAGES_PART_1,
  ...SEO_PAGES_PART_2,
  ...SEO_PAGES_PART_3,
  ...SEO_PAGES_PART_4,
  ...SEO_PAGES_PART_5,
  ...SEO_PAGES_PART_6,
  ...SEO_PAGES_PART_7,
  ...SEO_PAGES_PART_8,
  ...SEO_PAGES_PART_9,
  ...SEO_PAGES_PART_10,
  ...SEO_PAGES_PART_11,
  ...SEO_PAGES_PART_12,
  ...SEO_PAGES_SKINCARE,
  ...SEO_PAGES_CABELOS,
];

export const SEO_PAGE_BY_SLUG: Record<string, SeoPage> = Object.fromEntries(
  SEO_PAGES.map((p) => [p.slug, p]),
);

export function getSeoPagesByKind(kind: SeoPageKind) {
  return SEO_PAGES.filter((p) => p.kind === kind);
}

export function getRelatedSeoPages(page: SeoPage, limit = 8) {
  const pool = SEO_PAGES.filter(
    (p) => p.slug !== page.slug && p.kind !== "paraguai",
  );
  const sameBrand = page.brand
    ? pool.filter((p) => p.brand === page.brand && p.kind === "perfume")
    : [];
  const sameKind = pool.filter((p) => p.kind === page.kind);
  const merged = [...sameBrand, ...sameKind, ...pool];
  const seen = new Set<string>();
  const out: SeoPage[] = [];
  for (const p of merged) {
    if (seen.has(p.slug)) continue;
    seen.add(p.slug);
    out.push(p);
    if (out.length >= limit) break;
  }
  return out;
}
